(function(){"use strict";function $(id){return document.getElementById(id)}var widget=$("weeklyWidget");if(!widget)return;var head=widget.querySelector(".daily-widget-head");var body=widget.querySelector(".daily-widget-body");var foot=widget.querySelector(".daily-widget-foot");var claimedEl=$("dwClaimed");if(!head||!body)return;if(widget.getAttribute("data-dwc-init"))return;widget.setAttribute("data-dwc-init","1");var wrap=document.createElement("div");wrap.className="dwc-collapsible";wrap.id="dwcRegion";var inner=document.createElement("div");inner.className="dwc-inner";wrap.appendChild(inner);widget.insertBefore(wrap,body);inner.appendChild(body);if(foot)inner.appendChild(foot);var cd=head.querySelector(".daily-widget-cd");var chip=document.createElement("span");chip.className="dwc-chip";chip.innerHTML="\u2713 Cleared";head.insertBefore(chip,cd||null);var bragBtn=document.createElement("button");bragBtn.className="daily-btn daily-btn-mini dwc-brag";bragBtn.type="button";bragBtn.textContent="\u2197 Brag it";head.insertBefore(bragBtn,cd||null);bragBtn.addEventListener("click",function(){var orig=$("dwBrag");if(orig){orig.click();return}if(window.wgpBrag&&typeof window.wgpBrag.open==="function")window.wgpBrag.open()});var toggleBtn=document.createElement("button");toggleBtn.className="dwc-toggle";toggleBtn.type="button";toggleBtn.setAttribute("aria-label","Collapse or expand this week's challenge");toggleBtn.setAttribute("aria-controls","dwcRegion");toggleBtn.setAttribute("aria-expanded","true");toggleBtn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><path d="m6 9 6 6 6-6"/></svg>';head.appendChild(toggleBtn);var KEY="wgp_dwc_state_v1";function today(){return new Date().toDateString()}function readPref(){try{var s=JSON.parse(localStorage.getItem(KEY)||"{}");return s.day===today()?s:null}catch(e){return null}}function writePref(collapsed){try{localStorage.setItem(KEY,JSON.stringify({day:today(),collapsed}))}catch(e){}}function setCollapsed(c,persist){widget.classList.toggle("is-collapsed",c);toggleBtn.setAttribute("aria-expanded",String(!c));if(persist)writePref(c)}function markClaimed(){widget.classList.add("has-claimed")}function isClaimedVisible(){return claimedEl&&!claimedEl.hidden}if(isClaimedVisible()){markClaimed();var pref=readPref();widget.classList.add("dwc-noanim");setCollapsed(pref?!!pref.collapsed:true,false);void widget.offsetWidth;widget.classList.remove("dwc-noanim")}if(claimedEl&&window.MutationObserver){new MutationObserver(function(){if(!isClaimedVisible()||widget.classList.contains("has-claimed"))return;markClaimed();setTimeout(function(){var p=readPref();if(p&&p.collapsed===false)return;if(widget.classList.contains("is-collapsed"))return;setCollapsed(true,true)},1800)}).observe(claimedEl,{attributes:true,attributeFilter:["hidden"]})}head.addEventListener("click",function(e){if(!widget.classList.contains("has-claimed"))return;var btn=e.target.closest("button");if(btn&&!btn.classList.contains("dwc-toggle"))return;setCollapsed(!widget.classList.contains("is-collapsed"),true)})})();
